import axios from "axios";
import { createContext, useCallback, useContext, useState } from "react";

const ProgressContext = createContext();

export function ProgressProvider({ children }) {
  const [allProgress, setAllProgress] = useState([]);
  const [currentProgress, setCurrentProgress] = useState(null);

  const fetchAllProgress = useCallback(async () => {
    try {
      const { data } = await axios.get("/api/progress");
      setAllProgress(data);
    } catch (err) {
      console.error(err);
    }
  }, []);

  const fetchLessonProgress = useCallback(async (lessonId) => {
    try {
      const { data } = await axios.get(`/api/progress/${lessonId}`);
      setCurrentProgress(data);
      return data;
    } catch (err) {
      console.error(err);
      return null;
    }
  }, []);

  const markSection = useCallback(
    async (lessonId, level, day, section, quizScore) => {
      try {
        const { data } = await axios.post("/api/progress/update", {
          lessonId,
          level,
          day,
          section,
          quizScore,
        });
        setCurrentProgress(data);
        return data;
      } catch (err) {
        console.error(err);
      }
    },
    [],
  );

  return (
    <ProgressContext.Provider
      value={{
        allProgress,
        currentProgress,
        setCurrentProgress,
        fetchAllProgress,
        fetchLessonProgress,
        markSection,
      }}
    >
      {children}
    </ProgressContext.Provider>
  );
}

export const useProgress = () => useContext(ProgressContext);
